import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const ProgrammeMaster = () => {
    const [programmes, setProgrammes] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ department: '', programmeName: '', programmeShortName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [deptLoading, setDeptLoading] = useState(true);

    useEffect(() => {
        fetchProgrammes();
        fetchDepartments();
    }, []);

    const fetchProgrammes = async () => {
        try {
            const { data } = await API.get('/master/programme');
            setProgrammes(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching programmes' });
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
            console.log('Departments loaded:', data); // Debug log
        } catch (err) {
            console.error('Error fetching departments:', err); // Debug log
            setMessage({ type: 'error', text: 'Error fetching departments' });
        } finally {
            setDeptLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/programme', formData);
            setFormData({ department: '', programmeName: '', programmeShortName: '' });
            fetchProgrammes();
            setMessage({ type: 'success', text: '✓ Programme added successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error adding programme' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>📚 Programme Master</h1>
                    <p style={styles.subtitle}>Manage all academic programmes</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' 
                            ? '#f0fdf4' 
                            : '#fef2f2',
                        borderColor: message.type === 'success' ? '#22c55e' : '#ef4444',
                        color: message.type === 'success' ? '#15803d' : '#dc2626',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.container}>
                    <div style={styles.formSide}>
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGroup}>
                                <label style={styles.label}>
                                    Department
                                    {deptLoading && <span style={styles.loadingText}> (Loading...)</span>}
                                </label>
                                <select 
                                    required
                                    value={formData.department}
                                    onChange={e => setFormData({...formData, department: e.target.value})}
                                    style={styles.input}
                                    disabled={deptLoading}
                                >
                                    <option value="">Select Department</option>
                                    {departments.map(dept => (
                                        <option key={dept._id} value={dept._id}>
                                            {dept.department || dept.deptName || 'No name'}
                                        </option>
                                    ))}
                                </select>
                                {!deptLoading && departments.length === 0 && (
                                    <div style={styles.warningBox}>
                                        ⚠️ No departments found. Please add departments first.
                                    </div>
                                )}
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Programme Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.programmeName}
                                    onChange={e => setFormData({...formData, programmeName: e.target.value})}
                                    style={styles.input}
                                    placeholder="Enter programme name..."
                                    disabled={deptLoading || departments.length === 0}
                                />
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Short Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.programmeShortName}
                                    onChange={e => setFormData({...formData, programmeShortName: e.target.value})}
                                    style={styles.input}
                                    placeholder="e.g., BCA, MCA..."
                                    maxLength="5"
                                    disabled={deptLoading || departments.length === 0}
                                />
                            </div>

                            <button 
                                type="submit" 
                                disabled={loading || deptLoading || departments.length === 0} 
                                style={{
                                    ...styles.button, 
                                    opacity: (loading || deptLoading || departments.length === 0) ? 0.5 : 1,
                                    cursor: (loading || deptLoading || departments.length === 0) ? 'not-allowed' : 'pointer'
                                }}
                            >
                                {loading ? '⏳ Adding...' : '➕ Add Programme'}
                                {departments.length === 0 && !deptLoading && ' (No departments)'}
                            </button>
                        </form>
                    </div>

                    <div style={styles.tableSide}>
                        <h3 style={styles.tableTitle}>📋 Programme List</h3>
                        <div style={styles.tableContainer}>
                            <table style={styles.table}>
                                <thead>
                                    <tr style={styles.tableHeaderRow}>
                                        <th style={{...styles.tableHeader, width: '40%'}}>Department</th>
                                        <th style={{...styles.tableHeader, width: '35%'}}>Programme Name</th>
                                        <th style={{...styles.tableHeader, width: '25%'}}>Short Name</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {programmes.length > 0 ? (
                                        programmes.map((prog, idx) => (
                                            <tr key={prog._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                <td style={styles.tableCell}>
                                                    {prog.department?.deptName || prog.department?.department || 'N/A'}
                                                </td>
                                                <td style={styles.tableCell}>{prog.programmeName}</td>
                                                <td style={{...styles.tableCell, textAlign: 'center'}}>
                                                    <span style={styles.badge}>{prog.programmeShortName}</span>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr>
                                            <td colSpan="3" style={{...styles.tableCell, textAlign: 'center', color: '#6b7280'}}>
                                                No programmes found
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
